   134	// runSingleScopeSync runs the legacy single-scope sync against the nearest
   135	// (or explicit --workspace) scope. It preserves today's behavior verbatim and
   136	// is taken only when an explicit --workspace override is in effect; the
   137	// default path is the hierarchy orchestrator. validate also relies on this
   138	// single-scope shape via prepareEngine.
   139	func runSingleScopeSync(cmd *cobra.Command, rc *runtimeContext, opts engine.Options, postMerge bool, now time.Time) error {
   140		prep, err := prepareEngine(cmd.Context(), rc, now)
   141		if err != nil {
   142			return fmt.Errorf("sync: %w", err)
   143		}
   144		defer prep.Close()
   145	
   146		req := prep.Request
   147		req.Options = opts
   148	
   149		root := prep.Root
   150		summary, err := engine.Sync(cmd.Context(), req)
   151		if err != nil {
   152			return fmt.Errorf("sync: %w", err)
   153		}
   154	
   155		// Post-merge hook mode: if a target was blocked by an in-progress sync's
   156		// lock, write the skip marker and exit 0 so `git pull` is never broken
   157		// (plan U3 / AGENTS invariant #3 spirit).
   158		if postMerge && anyBlocked(summary) {
   159			if werr := writeHookSkipped(root, now); werr != nil {
   160				rc.Logger.Warn("sync: failed to write hook-skipped marker", "err", werr)
   161			}
   162			return nil
   163		}
   164	
   165		if err := renderSummary(cmd, rc.Access, summary); err != nil {
   166			return err
   167		}
   168		if summary.Outcome.ExitCode != 0 {
   169			return &exitError{code: summary.Outcome.ExitCode, err: errors.New("sync reported failures")}
   170		}
   171		return nil
   172	}
   173	
   174	// handleHierarchyPostMerge applies the post-merge yield across the hierarchy:
   175	// for each scope whose sync was blocked by an in-progress lock, it writes that
   176	// scope's hook-skipped marker. It returns true when any scope was blocked, in
   177	// which case the caller exits 0 so `git pull` is never broken. A blocked scope
   178	// has no engine error (the lock yield is a clean outcome), so its summary is
   179	// inspected via anyBlocked.
   180	func handleHierarchyPostMerge(rc *runtimeContext, outcomes []scopeOutcome, now time.Time) bool {
   181		handled := false
   182		for _, o := range outcomes {
   183			if o.Err != nil || !anyBlocked(o.Summary) {
   184				continue
   185			}
   186			handled = true
   187			root, err := fsroot.OpenWorkspaceRoot(o.Scope.Root)
   188			if err != nil {
   189				rc.Logger.Warn("sync: failed to open root for hook-skipped marker", "root", o.Scope.Root, "err", err)
   190				continue
   191			}
   192			if werr := writeHookSkipped(root, now); werr != nil {
   193				rc.Logger.Warn("sync: failed to write hook-skipped marker", "root", o.Scope.Root, "err", werr)
   194			}
   195			_ = root.Close()
   196		}
   197		return handled
   198	}
