   200	// promptYes writes a [Y/n] question to w (stderr — stdout stays data-only)
   201	// and reads one line from in. Enter and anything not starting with n/N is
   202	// yes. A read error (closed stdin, EOF) is a decline: never treat an
   203	// unanswerable prompt as consent to write the home directory.
   204	func promptYes(in io.Reader, w io.Writer, question string) bool {
   205		_, _ = fmt.Fprint(w, question)
   206		line, err := bufio.NewReader(in).ReadString('\n')
   207		if err != nil && line == "" {
   208			return false
   209		}
   210		answer := strings.TrimSpace(line)
   211		return answer == "" || (answer[0] != 'n' && answer[0] != 'N')
   212	}
